package vendor

import (
	"fmt"
	"os"
	"path/filepath"

	"gopkg.in/yaml.v3"
)

// LockfileName is the filename at the registry root that records
// per-vendor sync state and promotion lineage. Committed to git
// alongside csaw.yml so consumers of the registry get reproducible
// vendored state.
const LockfileName = "vendor.lock.yaml"

// lockfileHeader is written to the top of the file so a human reading
// it without context understands what it is and how to maintain it.
const lockfileHeader = `# csaw vendor lockfile — generated by csaw vendor sync.
# Records the upstream URL, resolved ref, and per-file SHA-256 for every
# vendored file, plus a lineage log of csaw vendor promote actions.
# Do not edit by hand. Run ` + "`csaw vendor sync`" + ` to update.
`

// LoadLockfile reads vendor.lock.yaml from the registry root. Returns an
// empty Lockfile (with Version=1) if the file doesn't exist — fresh
// registries with no vendors yet should not have an empty lockfile sitting
// around.
func LoadLockfile(registryRoot string) (*Lockfile, error) {
	path := filepath.Join(registryRoot, LockfileName)
	data, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			return &Lockfile{Version: 1, Vendors: map[string]VendorState{}}, nil
		}
		return nil, fmt.Errorf("read %s: %w", path, err)
	}

	var lf Lockfile
	if err := yaml.Unmarshal(data, &lf); err != nil {
		return nil, fmt.Errorf("parse %s: %w", path, err)
	}
	if lf.Version == 0 {
		lf.Version = 1
	}
	if lf.Vendors == nil {
		lf.Vendors = map[string]VendorState{}
	}
	return &lf, nil
}

// SaveLockfile writes the lockfile to the registry root atomically.
func SaveLockfile(registryRoot string, lf *Lockfile) error {
	if lf == nil {
		return fmt.Errorf("nil lockfile")
	}
	if lf.Version == 0 {
		lf.Version = 1
	}

	out, err := yaml.Marshal(lf)
	if err != nil {
		return fmt.Errorf("marshal lockfile: %w", err)
	}
	body := []byte(lockfileHeader + "\n" + string(out))

	path := filepath.Join(registryRoot, LockfileName)
	tmp := path + ".tmp"
	if err := os.WriteFile(tmp, body, 0o644); err != nil {
		return fmt.Errorf("write %s: %w", tmp, err)
	}
	if err := os.Rename(tmp, path); err != nil {
		_ = os.Remove(tmp)
		return fmt.Errorf("rename %s -> %s: %w", tmp, path, err)
	}
	return nil
}

// AppendPromotion records a new promotion in the lockfile's append-only
// log. Caller is responsible for calling SaveLockfile after.
func (lf *Lockfile) AppendPromotion(p Promotion) {
	lf.Promotions = append(lf.Promotions, p)
}
